SELECT WID.MATERIAL_ID AS materialId, NVL(SUM(WID.REMAINING_QUANTITY), 0) AS stockQuantity FROM E_MATERIAL_WAREHOUSE_IN_DETAIL WID INNER JOIN E_MATERIAL_WAREHOUSE_IN WI ON WID.WAREHOUSE_IN_ID = WI.ID AND WI.DEL_FLAG = 0 WHERE WID.MATERIAL_ID IN
#{materialId}
AND WI.WAREHOUSE_ID = #{warehouseId} AND WID.DEL_FLAG = 0 GROUP BY WID.MATERIAL_ID

mapper.update:
BEGIN
UPDATE E_MATERIAL_WAREHOUSE_IN_DETAIL SET OUT_QUANTITY = #{item.outQuantity,jdbcType=NUMERIC}, REMAINING_QUANTITY = #{item.remainingQuantity,jdbcType=NUMERIC}, UPDATE_BY = #{item.loginUserId,jdbcType=NUMERIC}, UPDATE_BY_NAME = #{item.loginUserName,jdbcType=VARCHAR}, UPDATE_TIME = SYSDATE WHERE ID = #{item.id};
END;
